sys_sg_data_item.query_condition_script:
(function getQueryString(input)
{
	var user = gs.getUserID();
	var offices = [];
	var grOUs = new GlideRecord('x_153465_discovert_discover_office_members');
	grOUs.addQuery('office_task_authority', 'true');
	grOUs.addQuery('office_member', user);
	grOUs.query();
	while(grOUs.next()){
		offices.push(grOUs.getValue('discover_office_hierarchy'));
	}
	if (offices.length > 0){
		var au = new global.ArrayUtil();
		offices = au.unique(offices);
	}

	var grGTA = new GlideRecord('x_153465_discovert_discover_office_members');
	grGTA.addQuery('office_member', user);

    return 'active=true^state=-5^ORstate=11^primary_assigneeIN' + offices.join() 
		 + '^NQactive=true^state=-5^ORstate=11';

})(input);
